class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int count = 0;
        while (num2) {
            count += num2 & 1;
            num2 >>= 1;
        }
        int res = 0;
        for (int i = 0; i < 31; i++) {
            if (count > 0 && (num1 >> i) & 1) {
                res |= 1 << i;
                count--;
            }
        }
        return res;
    }
};
```

